form:Form.form:Scripts:
		function LoadForm()
{
	EnableLegajo();
}

function EnableLegajo()
{
	if (Ctrl('oi_liquidacion').GetXValue() != '')
		CtrlEnabled('oi_personal_emp', true);
	else
	{
		CtrlEnabled('oi_personal_emp', false);	
		Ctrl('oi_personal_emp').SetXValue('');
	}
}

function SetLegajo()
{
	EnableLegajo();	
	var where = "PER02_PERSONAL_EMP.oi_personal_emp in (SELECT TTA10_LIQUIDACPERS.oi_personal_emp FROM TTA10_LIQUIDACPERS WHERE TTA10_LIQUIDACPERS.oi_liquidacion = " + Ctrl('oi_liquidacion').GetXValue() + ") ";
	var where_2 = "ORG03_EMPRESAS.oi_empresa in (SELECT PER02_PERSONAL_EMP.oi_empresa FROM TTA10_LIQUIDACPERS, PER02_PERSONAL_EMP JOIN TTA10_LIQUIDACPERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp WHERE TTA10_LIQUIDACPERS.oi_liquidacion =  " + Ctrl('oi_liquidacion').GetXValue() + ") ";	

	Ctrl('oi_personal_emp_2').SetWhere(where_2);
	Ctrl('oi_personal_emp').SetWhere(where);
}
